<head>
<style>
/*
  全局样式重置与容器定义
  风格：暗黑修仙、仪表盘、高质感
*/
:root {
  --bg-dark: #0a0a0a;
  --bg-card: rgba(30, 30, 30, 0.85);
  --border-gold: #b8860b;
  --border-red: #8b0000;
  --text-main: #e0e0e0;
  --text-dim: #888;
  --accent-red: #ff3333;
  --accent-gold: #ffd700;
  --font-main: 'Segoe UI', 'Microsoft YaHei', sans-serif;
}

.hud-container {
  display: grid;
  grid-template-areas:
    "header header"
    "status body"
    "npcs npcs"
    "hint hint";
  grid-template-columns: 1fr 1fr;
  gap: 8px;
  background: radial-gradient(circle at center, #1a1a1a 0%, #000 100%);
  border: 1px solid #333;
  border-top: 2px solid var(--border-gold);
  border-bottom: 2px solid var(--border-red);
  padding: 12px;
  border-radius: 4px;
  font-family: var(--font-main);
  color: var(--text-main);
  box-shadow: 0 10px 30px rgba(0,0,0,0.8);
  font-size: 13px;
  position: relative;
  overflow: hidden;
}

/* 背景纹理 */
.hud-container::before {
  content: "";
  position: absolute;
  top: 0; left: 0; width: 100%; height: 100%;
  background-image:
    linear-gradient(rgba(255,255,255,0.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.03) 1px, transparent 1px);
  background-size: 20px 20px;
  pointer-events: none;
  z-index: 0;
}

/* 通用模块样式 */
.hud-module {
  background: var(--bg-card);
  border: 1px solid rgba(255,255,255,0.1);
  padding: 8px 10px;
  position: relative;
  z-index: 1;
  border-radius: 2px;
  backdrop-filter: blur(2px);
  display: flex;
  flex-direction: column;
}

/* 区域 1: Header (时空信息) */
.area-header {
  grid-area: header;
