.area-body {
  grid-area: body;
  border-right: 2px solid var(--border-red);
}
.status-row {
  display: flex;
  justify-content: space-between;
  margin-bottom: 4px;
  align-items: center;
}
.label { color: var(--text-dim); font-size: 0.85em; }
.value { font-weight: 500; }

/* 血条设计 */
.hp-track {
  width: 100%;
  height: 6px;
  background: #333;
  margin: 4px 0 8px 0;
  position: relative;
  overflow: hidden;
  border: 1px solid #444;
}
.hp-fill {
