<script type="module">
import _ from 'https://cdn.jsdelivr.net/npm/lodash@4.17.21/+esm';

/* 数据填充 */
function updateHUD() {
    try {
        const vars = getAllVariables();
        /* 判空保护 */
        if (!vars || !vars.stat_data) return;

        const d = vars.stat_data;
        const mc = d.主角 || {};
        const world = d.世界 || {};
        const st = d.状态 || {};
        const npcs = d.npc || {};

        /* Header: 时空 */
        $('#hud-time').text(world.时间 || '混沌未分');
        $('#hud-loc').text(world.地点 || '虚空');

        /* Body: 肉身 */
        $('#hud-id').text(mc.身份 || '尘埃');
        $('#hud-semen').text(mc.精液储备 || '枯竭');

        const hp = parseInt(mc.身体状态) || 0;
        const $hpBar = $('#hud-hp-bar');
        $hpBar.css('width', hp + '%');
        $('#hud-hp-val').text(hp);

        /* 濒死特效 */
        if (hp < 20) $hpBar.addClass('critical');
        else $hpBar.removeClass('critical');

        /* 暴露等级 */
        const exp = parseInt(mc.暴露等级) || 0;
        const expColors = ['#4dff88', '#ffffaa', '#ffaa4d', '#ff4d4d', '#ff0000'];
        const expTexts = ['无人知晓', '私宠', '小圈子', '高层震动', '全界通缉'];
        const color = expColors[Math.min(exp, 4)];
        $('#hud-exp').text(`情报泄露: LV.${exp} ${expTexts[exp] || ''}`)
                     .css({borderColor: color, color: color, boxShadow: `0 0 5px ${color}33`});

        /* Status: 局势 */
        $('#hud-danger').text(st.危机 || '暂无');
        $('#hud-goal').text(st.目标 || '生存');
        $('#hud-hint').text(st.破局提示 || '静观其变...');

        /* NPCs: 众生列表 */
        const $npcList = $('#hud-npc-list');
        $npcList.empty();

        if (_.isEmpty(npcs)) {
            $npcList.html('<div style="width:100%;text-align:center;color:#555;padding:10px;">孤身一人</div>');
        } else {
            _.forEach(npcs, (n, name) => {
                const malice = n.恶意 || 0;
                const love = n.对主角的好感 || 0;
                /* 生成卡片 */
                $npcList.append(`
                  <div class="npc-item">
                    <div class="npc-top">
                      <span class="npc-name">${name}</span>
                      <span class="npc-power">${n.境界 || '?'}</span>
                    </div>
                    <div class="npc-detail" style="margin-bottom:2px">
                      <span>${n.当前认知 || '未知'}</span>
                    </div>
                    <div class="npc-detail">
                      <span style="color:#ff6666">🩸${malice}</span>
                      <span style="color:#ff99cc">💕${love}</span>
                    </div>
                  </div>
                `);
            });
        }

    } catch (e) {
        console.error('HUD Update Error:', e);
    }
}

async function init() {
    /* 立即执行一次 */
    updateHUD();
    /* 每秒刷新，确保实时性 */
    setInterval(updateHUD, 1000);
}

$(() => {
    if (typeof errorCatched !== 'undefined') {
        errorCatched(init)();
    } else {
        init();
    }
});
</script>
