import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  // 世界状态
  世界: z.object({
    时间: z.string().describe('当前的时间描述'),
    地点: z.string().describe('当前的具体位置'),
  }),

  // 主角状态
  主角: z.object({
    身份: z.string(),
    修为: z.literal('毫无修为'),
    精液储备: z.string().describe('当前精元的质地与余量描述'),
    身体状态: z.coerce.number().int().min(0).max(100).describe('生命体征数值，低于20濒死'),
    暴露等级: z.coerce.number().int().min(0).max(4).describe('秘密泄露的范围等级'),
  }),

  // 剧情驱动
  状态: z.object({
    危机: z.string().describe('当前面临的紧迫威胁'),
    目标: z.string().describe('当前的短期行动目标'),
    // 新增：破局指引
    破局提示: z.string().describe('系统给予的生存建议或线索'),
  }),

  // 动态NPC列表
  npc: z.record(z.string(), z.object({
    衣着: z.string(),
    境界: z.string().describe('如炼气九层、筑基初期'),
    当前认知: z.string(),
    对主角的好感: z.coerce.number(),
    恶意: z.coerce.number(),
  })),
});

$(() => {
  registerMvuSchema(Schema);
})
